  1→import React, {useCallback, useEffect, useMemo, useState} from 'react';
  2→import {ActivityIndicator, Image, StyleSheet, View} from 'react-native';
  3→import {useQuery} from '@tanstack/react-query';
  4→import {NativeStackScreenProps} from '@react-navigation/native-stack';
  5→import {SafeAreaView} from 'react-native-safe-area-context';
  6→import LinearGradient from 'react-native-linear-gradient';
  7→import {useAuth} from '../../features/auth/AuthProvider';
  8→import {useTheme} from '../../theme/ThemeProvider';
  9→import {mobileApi} from '../../lib/api/mobileApi';
 10→import {socialApi} from '../../lib/api/socialApi';
 11→import {useFollowMutation} from '../../hooks/useFollowMutation';
 12→import {ProfileHeroSection} from './ProfileHeroSection';
 13→import {ProfileTabBar, type ProfileTab} from './ProfileTabBar';
 14→import {ProfileWritingsTab} from './ProfileWritingsTab';
 15→import {ProfileStoriesTab} from './ProfileStoriesTab';
 16→import {ProfileOpinionsTab} from './ProfileOpinionsTab';
 17→import {ProfileMediaTab} from './ProfileMediaTab';
 18→import {PrimaryButton} from '../../components/PrimaryButton';
 19→import {
 20→  parseProfileBackground,
 21→  cssAngleToGradientPoints,
 22→} from '../../lib/utils/profileBackground';
 23→import type {RootStackParamList} from '../../navigation/types';
 24→
 25→type Props = NativeStackScreenProps<RootStackParamList, 'VisitProfile'>;
 26→
 27→export function VisitProfileScreen({route, navigation}: Props) {
 28→  const {userId} = route.params;
 29→  const {user, session} = useAuth();
 30→  const {colors} = useTheme();
 31→  const [activeTab, setActiveTab] = useState<ProfileTab>('writings');
 32→
 33→  // Self-redirect guard
 34→  useEffect(() => {
 35→    if (userId === user?.id) {
 36→      navigation.replace('Main' as any, {screen: 'Profile'});
 37→    }
 38→  }, [userId, user?.id, navigation]);
 39→
 40→  const userDataQuery = useQuery({
 41→    queryKey: ['profile', userId],
 42→    enabled: Boolean(userId) && userId !== user?.id,
 43→    queryFn: () => mobileApi.getUserData(userId),
 44→  });
 45→
 46→  const streakQuery = useQuery({
 47→    queryKey: ['streak', userId],
 48→    enabled: Boolean(userId) && userId !== user?.id,
 49→    queryFn: () => mobileApi.getStreak(userId),
 50→  });
 51→
 52→  const profile = userDataQuery.data?.userData?.[0] ?? null;
 53→  const streak = streakQuery.data?.currentStreak;
 54→  const longestStreak = streakQuery.data?.longestStreak;
 55→
 56→  // Set header title dynamically
 57→  useEffect(() => {
 58→    if (profile?.name) {
 59→      navigation.setOptions({title: profile.name});
 60→    }
 61→  }, [profile?.name, navigation]);
 62→
 63→  const parsedBg = useMemo(
 64→    () => parseProfileBackground(profile?.background),
 65→    [profile?.background],
 66→  );
 67→
 68→  const onFollowersPress = useCallback(() => {
 69→    navigation.navigate('FollowList', {userId, tab: 'followers'});
 70→  }, [navigation, userId]);
 71→
 72→  const onFollowingPress = useCallback(() => {
 73→    navigation.navigate('FollowList', {userId, tab: 'following'});
 74→  }, [navigation, userId]);
 75→
 76→  const token = session?.access_token ?? '';
 77→
 78→  const followsQuery = useQuery({
 79→    queryKey: ['followsData', userId],
 80→    enabled: Boolean(token && userId) && userId !== user?.id,
 81→    queryFn: () => socialApi.getFollowsData(token, userId),
 82→  });
 83→
 84→  const isFollowing = followsQuery.data?.isFollowing ?? false;
 85→  const followMutation = useFollowMutation(token, userId);
 86→
 87→  if (userId === user?.id) {
 88→    return null;
 89→  }
 90→
 91→  if (userDataQuery.isLoading) {
 92→    return (
 93→      <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]}>
 94→        <View style={styles.loadingContainer}>
 95→          <ActivityIndicator color={colors.loaderColor} size="large" />
 96→        </View>
 97→      </SafeAreaView>
 98→    );
 99→  }
100→
101→  const followButton = (
102→    <PrimaryButton
103→      label={followMutation.isPending ? '...' : isFollowing ? 'Following' : 'Follow'}
104→      onPress={() => followMutation.mutate()}
105→      kind={isFollowing ? 'secondary' : 'primary'}
106→      loading={followMutation.isPending}
107→    />
108→  );
109→
110→  const headerComponent = (
111→    <View>
112→      <ProfileHeroSection
113→        profile={profile}
114→        streak={streak}
115→        longestStreak={longestStreak}
116→        onFollowersPress={onFollowersPress}
117→        onFollowingPress={onFollowingPress}
118→        actionButton={followButton}
119→      />
120→      <ProfileTabBar activeTab={activeTab} onTabChange={setActiveTab} />
121→      <View style={styles.tabSpacer} />
122→    </View>
123→  );
124→
125→  const backdropElement = useMemo(() => {
126→    if (parsedBg.type === 'gradient') {
127→      const {start, end} = cssAngleToGradientPoints(parsedBg.angle);
128→      return (
129→        <LinearGradient
130→          colors={parsedBg.colors}
131→          locations={parsedBg.locations}
132→          start={start}
133→          end={end}
134→          style={[StyleSheet.absoluteFill, styles.backdrop]}
135→        />
136→      );
137→    }
138→    if (parsedBg.type === 'image') {
139→      const dominantArr = profile?.dominant_colors
140→        ? profile.dominant_colors.split(',').map(c => c.trim())
141→        : null;
142→      const secondaryArr = profile?.secondary_colors
143→        ? profile.secondary_colors.split(',').map(c => c.trim())
144→        : null;
145→      const hasGradientOverlay =
146→        dominantArr && dominantArr.length > 0 && secondaryArr && secondaryArr.length > 0;
147→      return (
148→        <View style={[StyleSheet.absoluteFill, styles.backdrop]}>
149→          {hasGradientOverlay && (
150→            <LinearGradient
151→              colors={[...dominantArr, ...secondaryArr]}
152→              style={StyleSheet.absoluteFill}
153→            />
154→          )}
155→          <Image
156→            source={{uri: parsedBg.uri}}
157→            blurRadius={40}
158→            style={[StyleSheet.absoluteFill, {opacity: 0.3}]}
159→            resizeMode="cover"
160→          />
161→        </View>
162→      );
163→    }
164→    return null;
165→  }, [parsedBg, profile?.dominant_colors, profile?.secondary_colors]);
166→
167→  return (
168→    <SafeAreaView
169→      style={[styles.safe, {backgroundColor: colors.bgPrimary}]}
170→      edges={['top']}>
171→      {backdropElement}
172→
173→      {activeTab === 'writings' ? (
174→        <ProfileWritingsTab
175→          userId={userId}
176→          headerComponent={headerComponent}
177→        />
178→      ) : activeTab === 'stories' ? (
179→        <ProfileStoriesTab
180→          userId={userId}
181→          headerComponent={headerComponent}
182→        />
183→      ) : activeTab === 'opinions' ? (
184→        <ProfileOpinionsTab
185→          userId={userId}
186→          headerComponent={headerComponent}
187→        />
188→      ) : activeTab === 'media' ? (
189→        <ProfileMediaTab
190→          userId={userId}
191→          headerComponent={headerComponent}
192→        />
193→      ) : (
194→        <ProfileStoriesTab
195→          userId={userId}
196→          headerComponent={headerComponent}
197→        />
198→      )}
199→    </SafeAreaView>
200→  );
201→}
202→
203→const styles = StyleSheet.create({
204→  safe: {
205→    flex: 1,
206→  },
207→  loadingContainer: {
208→    flex: 1,
209→    alignItems: 'center',
210→    justifyContent: 'center',
211→  },
212→  tabSpacer: {
213→    height: 12,
214→  },
215→  backdrop: {
216→    opacity: 0.15,
217→    transform: [{scale: 1.4}],
218→  },
219→});
