 1→import React from 'react';
 2→import {Pressable, StyleSheet, Text, View} from 'react-native';
 3→import {useTheme} from '../../theme/ThemeProvider';
 4→import {fonts} from '../../theme/typography';
 5→import {spacing} from '../../theme/spacing';
 6→
 7→export type ProfileTab = 'writings' | 'stories' | 'opinions' | 'media';
 8→
 9→interface ProfileTabBarProps {
10→  activeTab: ProfileTab;
11→  onTabChange: (tab: ProfileTab) => void;
12→}
13→
14→const TABS: {key: ProfileTab; label: string}[] = [
15→  {key: 'writings', label: 'Writings'},
16→  {key: 'stories', label: 'Stories'},
17→  {key: 'opinions', label: 'Opinions'},
18→  {key: 'media', label: 'Media'},
19→];
20→
21→export function ProfileTabBar({activeTab, onTabChange}: ProfileTabBarProps) {
22→  const {colors} = useTheme();
23→
24→  return (
25→    <View style={[styles.container, {borderBottomColor: colors.borderCard}]}>
26→      {TABS.map(tab => {
27→        const active = activeTab === tab.key;
28→        return (
29→          <Pressable
30→            key={tab.key}
31→            style={styles.tab}
32→            onPress={() => onTabChange(tab.key)}>
33→            <Text
34→              style={[
35→                styles.tabText,
36→                {
37→                  color: active ? colors.textHeading : colors.textMuted,
38→                  fontFamily: active ? fonts.ui.semiBold : fonts.ui.regular,
39→                },
40→              ]}>
41→              {tab.label}
42→            </Text>
43→            {active ? (
44→              <View style={[styles.indicator, {backgroundColor: colors.accentAmber}]} />
45→            ) : null}
46→          </Pressable>
47→        );
48→      })}
49→    </View>
50→  );
51→}
